import React, { useEffect, useState } from "react";
import dft from "../../images/default.jpeg";
import { useNavigate } from "react-router-dom";
import Button from "../../components/Button";
import { IconHome } from "@tabler/icons-react";
const Followers = () => {
  const [FollowingList, setFollowingList] = useState([]);
  const [FollowerList, setFollowerList] = useState([]);
  const navigate = useNavigate();
  useEffect(() => {
    const fetchSaves = async () => {
      const response = await fetch("http://localhost:8000/api/followShow", {
        method: "GET",
        headers: {
          "content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
      });
      const data = await response.json();
      console.log(data?.followerList, data?.followingList);
      setFollowerList(data?.followerList);
      setFollowingList(data?.followingList);
    };
    fetchSaves();
  }, []);
  return (
    <div>
      <div className="bg-[#dde3f6] flex flex-col items-center">
      <div className="flex items-center w-[100%] h-[100%] justify-center border-b pb-[7px]">
        <Button
          label={
            <div className="flex">
              <IconHome />
              <p>Home</p>
            </div>
          }
          className="fixed top-2 left-2 bg-[#7684cf] hover:bg-[#4f5ebb] rounded-2xl font-sans text-xl"
          onChange={() => navigate("/")}
        />
        <h1 className="font-bold text-[30px]">Followers</h1>
        <h1 className="font-bold text-[30px]">Following</h1>
      </div>
        {FollowerList?.map(({ followerId }) => {
            return (
              <div
                className="h-[55px] flex border-b cursor-pointer"
                onClick={() => navigate(`/user/${followerId?.userName}`)}
              >
                <img
                  src={followerId?.profilePic || dft}
                  alt="ProfilePic"
                  className="h-[50px] w-[50px] rounded-3xl relative left-[5px]"
                />
                <div className="flex justify-center ml-[10px]">
                  <p className="flex justify-center items-center ml-[20px] text-[25px]">{followerId?.userName}</p>
                </div>
              </div>
            );
          })}
        </div>
        <div className="w-[50%] flex flex-col items-center ">
          {FollowingList?.map(({ followedId }) => {
            return (
              <div
                className="h-[55px] flex border-b cursor-pointer"
                onClick={() => navigate(`/user/${followedId?.userName}`)}
              >
                <img
                  src={followedId?.profilePic || dft}
                  alt="ProfilePic"
                  className="h-[40px] w-[40px] rounded-3xl relative left-[5px]"
                />
                <div className="flex justify-center ml-[10px]">
                  <p className="flex justify-center items-center ml-[20px] text-[25px]">{followedId?.userName}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
  );
};

export default Followers;
